<?phpclass Rest {    private $domain = '192.185.28.57/~tserver/api/';    private $api_key;    private $username;    private $password;    public function __construct($domain = null, $api_key = null, $user_name = null, $password = null) {        $this->domain = $domain;        $this->api_key = $api_key;        $this->username = $user_name;        $this->password = $password;    }    protected function objectToArray($d) {        if (is_object($d)) {            // Gets the properties of the given object            // with get_object_vars function            $d = get_object_vars($d);        }        if (is_array($d)) {            /*             * Return array converted to object             * Using __FUNCTION__ (Magic constant)             * for recursive call             */            return array_map(__FUNCTION__, $d);        } else {            // Return array            return $d;        }    }    protected function sendRequest($uri, $data = array(), $method = 'GET', $format = 'JSON') {        $ch = curl_init();        $url = "http://" . $this->domain . $uri;        curl_setopt($ch, CURLOPT_URL, $url);        curl_setopt($ch, CURLOPT_SSL_VERIFYPEER, false);        curl_setopt($ch, CURLOPT_SSL_VERIFYHOST, 2);        curl_setopt($ch, CURLOPT_FOLLOWLOCATION, false);        curl_setopt($ch, CURLOPT_MAXREDIRS, 1);        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);//        if ($format == 'XML') {//            curl_setopt($ch, CURLOPT_HTTPHEADER, array(//                'Content-Type: application/xml',//                'Accept: application/xml'//            ));////        } else {////            curl_setopt($ch, CURLOPT_HTTPHEADER, array(////                'Content-Type: application/json',////                'Accept: application/json'////            ));//        }        curl_setopt($ch, CURLOPT_USERPWD, $this->username . ':' . $this->password);        $method = strtoupper($method);        if ($method == 'POST') {            curl_setopt($ch, CURLOPT_POST, true);            curl_setopt($ch, CURLOPT_POSTFIELDS, http_build_query($data));        } else if ($method == 'PUT') {            curl_setopt($ch, CURLOPT_CUSTOMREQUEST, 'PUT');            curl_setopt($ch, CURLOPT_POSTFIELDS, $data);        } else if ($method != 'GET') {            curl_setopt($ch, CURLOPT_CUSTOMREQUEST, $method);        }        curl_setopt($ch, CURLOPT_CONNECTTIMEOUT, 10);        curl_setopt($ch, CURLOPT_TIMEOUT, 30);//        $result = new StdClass();        $response = curl_exec($ch);        $code = curl_getinfo($ch, CURLINFO_HTTP_CODE);        $meta = curl_getinfo($ch);        $curl_error = ($code > 0 ? null : curl_error($ch) . ' (' . curl_errno($ch) . ')');        curl_close($ch);        if ($curl_error) {            echo "<pre>";            print_r($curl_error);            echo "</pre>";            throw new Exception('An error occurred while connecting to CloudNine: ' . $curl_error);        }        return $response;    }}class APIFormPrinting extends Rest {    public function getFormData($filter) {        $base_url = 'index.php?route=oauth/form_printing/postFormData';        return $this->sendRequest($base_url,$filter,'POST');    }    public function getRows($data) {//        d(http_build_query($data));        $base_url = 'index.php?route=oauth/form_printing/getRows';        return $this->sendRequest($base_url,$data,'POST');    }}class APIReport extends Rest {    public function PaidIndicator($data) {        $base_url = 'index.php?route=oauth/report/PaidIndicator';        return $this->sendRequest($base_url,$data,'POST');    }}?>